// Ce script suppose que chaque item entrant est UN message Discord.
// Il formate tous les messages dans un texte unique en français.

const items = $input.all();

const blocks = items.map((item) => {
  const msg = item.json;
  const author = msg.author || {};

  // Nom d'affichage si disponible, sinon username
  const username =
    author.global_name || author.username || "Utilisateur inconnu";

  // Format de date en français (Fuseau horaire France)
  const date = new Date(msg.timestamp);
  const formattedDate = date.toLocaleString("fr-FR", {
    timeZone: "Europe/Paris",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
  });

  const content = msg.content || "";

  return `${username} a dit le ${formattedDate} :\n${content}\n---`;
});

// Fusion des messages
const merged = blocks.join("\n");

return {
  json: {
    chatInput: merged,
  },
};

return {
